"use client";

import { motion } from "framer-motion";
import { portfolioData } from "@/data/portfolio";
import { Card, CardContent } from "@/components/ui/Card";
import { BookOpen, Target, GraduationCap } from "lucide-react";

export default function About() {
    return (
        <div className="section-padding space-y-20">
            <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                className="max-w-3xl space-y-8"
            >
                <h1 className="text-4xl md:text-6xl font-bold tracking-tight">About Me</h1>
                <p className="text-xl text-muted-foreground leading-relaxed">
                    {portfolioData.summary} {portfolioData.objective}
                </p>
            </motion.div>

            <div className="grid md:grid-cols-2 gap-8">
                <motion.div
                    initial={{ opacity: 0, x: -20 }}
                    animate={{ opacity: 1, x: 0 }}
                    transition={{ delay: 0.2 }}
                >
                    <Card className="h-full">
                        <CardContent className="p-8 space-y-4">
                            <div className="flex items-center gap-3 text-primary">
                                <Target size={24} />
                                <h2 className="text-xl font-bold">My Focus</h2>
                            </div>
                            <p className="text-muted-foreground leading-relaxed">
                                As a Software Engineering student, I specialize in building efficient, user-friendly applications. My current focus is on mobile development with Flutter and web technologies like React, with a strong emphasis on clean code and UI/UX implementation.
                            </p>
                        </CardContent>
                    </Card>
                </motion.div>

                <motion.div
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    transition={{ delay: 0.3 }}
                >
                    <Card className="h-full">
                        <CardContent className="p-8 space-y-6">
                            <div className="flex items-center gap-3 text-primary">
                                <GraduationCap size={24} />
                                <h2 className="text-xl font-bold">Education</h2>
                            </div>
                            <div className="space-y-6">
                                {portfolioData.education.map((edu, idx) => (
                                    <div key={idx} className="space-y-1">
                                        <p className="font-bold text-sm uppercase tracking-wider text-primary">{edu.period}</p>
                                        <p className="font-semibold">{edu.degree}</p>
                                        <p className="text-sm text-muted-foreground">{edu.institution}</p>
                                        {edu.details && <p className="text-xs font-bold text-primary/80">{edu.details}</p>}
                                    </div>
                                ))}
                            </div>
                        </CardContent>
                    </Card>
                </motion.div>
            </div>

            <section className="space-y-8">
                <h2 className="text-3xl font-bold">Approach & Principles</h2>
                <div className="grid sm:grid-cols-3 gap-6">
                    {[
                        { title: "Efficiency", desc: "Developing optimized code and database structures for fast, reliable application performance." },
                        { title: "Clean UI", desc: "Prioritizing user experience through modern, aesthetic, and intuitive interface designs." },
                        { title: "Maintainability", desc: "Writing clear, well-documented code that is easy to scale and collaborate on." }
                    ].map((item, idx) => (
                        <motion.div
                            key={item.title}
                            initial={{ opacity: 0, y: 10 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: 0.4 + idx * 0.1 }}
                            className="space-y-2 p-6 rounded-2xl bg-accent/10 border border-border"
                        >
                            <h3 className="text-lg font-bold text-primary">{item.title}</h3>
                            <p className="text-muted-foreground text-sm">{item.desc}</p>
                        </motion.div>
                    ))}
                </div>
            </section>
        </div>
    );
}

"use client";

import { motion } from "framer-motion";
import { Send, Mail, MapPin, Linkedin, Github } from "lucide-react";
import { Button } from "@/components/ui/Button";
import { Card, CardContent } from "@/components/ui/Card";
import { useState } from "react";
import { portfolioData } from "@/data/portfolio";

export default function Contact() {
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [isSuccess, setIsSuccess] = useState(false);

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        setIsSubmitting(true);
        // Simulate API call
        setTimeout(() => {
            setIsSubmitting(false);
            setIsSuccess(true);
        }, 1500);
    };

    return (
        <div className="section-padding space-y-16">
            <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                className="max-w-3xl space-y-6"
            >
                <h1 className="text-4xl md:text-6xl font-bold tracking-tight">Let's Connect</h1>
                <p className="text-xl text-muted-foreground leading-relaxed">
                    I'm always open to discussing new projects, creative ideas or technical collaborations. Feel free to reach out via the form below or through my social channels.
                </p>
            </motion.div>

            <div className="grid lg:grid-cols-3 gap-12">
                {/* Contact Info */}
                <div className="space-y-8">
                    {[
                        { icon: <Mail size={20} />, label: "Email", value: portfolioData.email },
                        { icon: <Linkedin size={20} />, label: "LinkedIn", value: "Minahil Anjum" },
                        { icon: <Github size={20} />, label: "GitHub", value: "minahil-ch" },
                        { icon: <MapPin size={20} />, label: "Location", value: "Vehari, Pakistan" },
                    ].map((item, idx) => (
                        <motion.div
                            key={item.label}
                            initial={{ opacity: 0, x: -20 }}
                            animate={{ opacity: 1, x: 0 }}
                            transition={{ delay: idx * 0.1 }}
                            className="flex items-center gap-4 group"
                        >
                            <div className="p-3 rounded-full bg-primary/10 text-primary group-hover:bg-primary group-hover:text-primary-foreground transition-all duration-300">
                                {item.icon}
                            </div>
                            <div>
                                <p className="text-xs font-bold uppercase tracking-widest text-muted-foreground">{item.label}</p>
                                <p className="font-medium">{item.value}</p>
                            </div>
                        </motion.div>
                    ))}
                </div>

                {/* Contact Form */}
                <motion.div
                    initial={{ opacity: 0, scale: 0.95 }}
                    animate={{ opacity: 1, scale: 1 }}
                    className="lg:col-span-2"
                >
                    <Card className="p-8">
                        {isSuccess ? (
                            <motion.div
                                initial={{ opacity: 0, y: 10 }}
                                animate={{ opacity: 1, y: 0 }}
                                className="text-center py-12 space-y-4"
                            >
                                <div className="w-16 h-16 bg-green-500/10 text-green-500 rounded-full flex justify-center items-center mx-auto">
                                    <Send size={32} />
                                </div>
                                <h2 className="text-2xl font-bold">Message Sent!</h2>
                                <p className="text-muted-foreground">Thank you for reaching out. I'll get back to you within 24 hours.</p>
                                <Button variant="ghost" onClick={() => setIsSuccess(false)}>Send another message</Button>
                            </motion.div>
                        ) : (
                            <form onSubmit={handleSubmit} className="space-y-6">
                                <div className="grid sm:grid-cols-2 gap-6">
                                    <div className="space-y-2">
                                        <label className="text-sm font-bold uppercase tracking-wider">Name</label>
                                        <input
                                            required
                                            className="w-full bg-accent/20 border-border rounded-lg p-3 outline-none focus:ring-2 focus:ring-primary/50 transition-all shadow-sm"
                                            placeholder="Jane Doe"
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <label className="text-sm font-bold uppercase tracking-wider">Email</label>
                                        <input
                                            required
                                            type="email"
                                            className="w-full bg-accent/20 border-border rounded-lg p-3 outline-none focus:ring-2 focus:ring-primary/50 transition-all shadow-sm"
                                            placeholder="jane@example.com"
                                        />
                                    </div>
                                </div>
                                <div className="space-y-2">
                                    <label className="text-sm font-bold uppercase tracking-wider">Subject</label>
                                    <input
                                        required
                                        className="w-full bg-accent/20 border-border rounded-lg p-3 outline-none focus:ring-2 focus:ring-primary/50 transition-all shadow-sm"
                                        placeholder="Project Inquiry"
                                    />
                                </div>
                                <div className="space-y-2">
                                    <label className="text-sm font-bold uppercase tracking-wider">Message</label>
                                    <textarea
                                        required
                                        rows={5}
                                        className="w-full bg-accent/20 border-border rounded-lg p-3 outline-none focus:ring-2 focus:ring-primary/50 transition-all shadow-sm resize-none"
                                        placeholder="Tell me about your project..."
                                    />
                                </div>
                                <Button
                                    size="lg"
                                    className="w-full font-bold tracking-widest uppercase gap-2"
                                    disabled={isSubmitting}
                                >
                                    {isSubmitting ? "Sending..." : "Send Message"}
                                    <Send size={18} />
                                </Button>
                            </form>
                        )}
                    </Card>
                </motion.div>
            </div>
        </div>
    );
}

"use client";

import { motion } from "framer-motion";
import { portfolioData } from "@/data/portfolio";
import { Card, CardHeader, CardTitle, CardDescription, CardContent, CardFooter } from "@/components/ui/Card";
import { Badge } from "@/components/ui/Badge";
import { Button } from "@/components/ui/Button";
import { ExternalLink, Github } from "lucide-react";
import Link from "next/link";
import Image from "next/image";

export default function Projects() {
    return (
        <div className="section-padding space-y-16">
            <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                className="max-w-3xl space-y-6"
            >
                <h1 className="text-4xl md:text-6xl font-bold tracking-tight">Project Showcase</h1>
                <p className="text-xl text-muted-foreground leading-relaxed">
                    A collection of high-impact projects where I've applied my technical skills to solve real-world problems.
                </p>
            </motion.div>

            <div className="grid lg:grid-cols-2 gap-10">
                {portfolioData.projects.map((project, idx) => (
                    <motion.div
                        key={project.id}
                        initial={{ opacity: 0, scale: 0.95 }}
                        animate={{ opacity: 1, scale: 1 }}
                        transition={{ delay: idx * 0.15 }}
                    >
                        <Card className="overflow-hidden group flex flex-col h-full">
                            <div className="relative aspect-video overflow-hidden">
                                <Image
                                    src={project.image}
                                    alt={project.name}
                                    fill
                                    className="object-cover transition-transform duration-500 group-hover:scale-110"
                                />
                                <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-4">
                                    <a href={project.github} target="_blank" rel="noopener noreferrer">
                                        <Button variant="secondary" size="sm" className="rounded-full"><Github size={18} /></Button>
                                    </a>
                                    <Link href={`/projects/${project.slug}`}>
                                        <Button variant="secondary" size="sm" className="rounded-full">Details</Button>
                                    </Link>
                                </div>
                            </div>
                            <CardHeader>
                                <div className="flex flex-wrap gap-2 mb-3">
                                    {project.tech.map((t) => (
                                        <Badge key={t} variant="outline" className="text-[10px] uppercase font-bold tracking-wider">{t}</Badge>
                                    ))}
                                </div>
                                <CardTitle className="text-2xl group-hover:text-primary transition-colors">
                                    {project.name}
                                </CardTitle>
                                <CardDescription className="line-clamp-2 text-base pt-2">
                                    {project.solution}
                                </CardDescription>
                            </CardHeader>
                            <CardContent className="flex-grow">
                                <p className="text-sm font-semibold text-primary uppercase tracking-widest">Problem Statement:</p>
                                <p className="text-sm text-muted-foreground mt-2 italic">
                                    "{project.problem}"
                                </p>
                            </CardContent>
                            <CardFooter className="pt-0 justify-between">
                                <Link href={`/projects/${project.slug}`}>
                                    <Button variant="ghost" className="gap-2">View Case Study <ExternalLink size={16} /></Button>
                                </Link>
                            </CardFooter>
                        </Card>
                    </motion.div>
                ))}
            </div>
        </div>
    );
}

"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { Moon, Sun, Menu, X } from "lucide-react";
import { useTheme } from "next-themes";
import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";

const navLinks = [
    { name: "Home", href: "/" },
    { name: "About", href: "/about" },
    { name: "Skills", href: "/skills" },
    { name: "Projects", href: "/projects" },
    { name: "Experience", href: "/experience" },
    { name: "Resume", href: "/resume" },
    { name: "Contact", href: "/contact" },
];

export default function Navbar() {
    const pathname = usePathname();
    const { theme, setTheme } = useTheme();
    const [mounted, setMounted] = useState(false);
    const [isOpen, setIsOpen] = useState(false);

    useEffect(() => setMounted(true), []);

    if (!mounted) return null;

    return (
        <nav className="sticky top-0 z-50 w-full glass">
            <div className="max-w-7xl mx-auto px-6 h-16 flex items-center justify-between">
                <Link href="/" className="text-xl font-bold tracking-tighter">
                    MINAHIL<span className="text-primary/50">.</span>
                </Link>

                {/* Desktop Nav */}
                <div className="hidden md:flex items-center gap-8">
                    {navLinks.map((link) => (
                        <Link
                            key={link.href}
                            href={link.href}
                            className={`text-sm font-medium transition-colors hover:text-primary ${pathname === link.href ? "text-primary font-semibold" : "text-muted-foreground"
                                }`}
                        >
                            {link.name}
                        </Link>
                    ))}
                    <button
                        onClick={() => setTheme(theme === "dark" ? "light" : "dark")}
                        className="p-2 rounded-full hover:bg-accent transition-colors"
                    >
                        {theme === "dark" ? <Sun size={18} /> : <Moon size={18} />}
                    </button>
                </div>

                {/* Mobile Toggle */}
                <div className="md:hidden flex items-center gap-4">
                    <button
                        onClick={() => setTheme(theme === "dark" ? "light" : "dark")}
                        className="p-2 rounded-full hover:bg-accent"
                    >
                        {theme === "dark" ? <Sun size={18} /> : <Moon size={18} />}
                    </button>
                    <button onClick={() => setIsOpen(!isOpen)} className="p-2">
                        {isOpen ? <X size={24} /> : <Menu size={24} />}
                    </button>
                </div>
            </div>

            {/* Mobile Menu */}
            <AnimatePresence>
                {isOpen && (
                    <motion.div
                        initial={{ opacity: 0, y: -20 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: -20 }}
                        className="md:hidden absolute top-16 left-0 w-full bg-background border-b border-border p-6 flex flex-col gap-4"
                    >
                        {navLinks.map((link) => (
                            <Link
                                key={link.href}
                                href={link.href}
                                onClick={() => setIsOpen(false)}
                                className={`text-lg font-medium ${pathname === link.href ? "text-primary" : "text-muted-foreground"
                                    }`}
                            >
                                {link.name}
                            </Link>
                        ))}
                    </motion.div>
                )}
            </AnimatePresence>
        </nav>
    );
}
